import { Map } from "../core/map";
import { IControl } from "./control";

import { ControlPosition as maplibreControlPosition, Listener as maplibreListener } from "maplibre-gl";

/**
 * Options for configuring the {@link SearchControl}.
 */
export type SearchControlOptions = {};

/**
 * Default options for the {@link SearchControl}.
 */
export const defaultSearchControlOptions: SearchControlOptions = {};

const modifierKeys = ["Control", "Shift", "Alt", "AltGraph", "Meta"];
const navigationKeys = ["ArrowUp", "ArrowDown", "ArrowLeft", "ArrowRight"];
const functionKeys = ["F1", "F2", "F3", "F4", "F5", "F6", "F7", "F8", "F9", "F10", "F11", "F12"];
const otherKeys = ["CapsLock", "Tab", "Escape", "Enter", "ContextMenu", "Insert", "Home", "End", "PageUp", "PageDown", "ScrollLock", "Pause", "Dead"];

function isInputKey(key: KeyboardEvent["key"]) {
  return !modifierKeys.includes(key) && !navigationKeys.includes(key) && !otherKeys.includes(key) && !functionKeys.includes(key);
}

function isNavigationKey(key: KeyboardEvent["key"]) {
  return navigationKeys.includes(key);
}

/**
 * Provides a search input.
 */
export class SearchControl implements IControl {
  options: SearchControlOptions;
  _container: HTMLElement;

  _map?: Map;
  _onInput?: EventListener;
  _onKeyDown?: EventListener;

  /**
   * @param options - Options for configuring the search control.
   */
  constructor(options?: SearchControlOptions) {
    this.options = Object.assign(defaultSearchControlOptions, options);

    this._container = document.createElement("div");
    this._container.classList.add("maplibregl-ctrl", "maptoolkit-ctrl", "maptoolkit-ctrl-search");

    let _debounce: ReturnType<typeof setTimeout>;
    this._onInput = (ev: Event) => {
      if (_debounce) {
        clearTimeout(_debounce);
      }
      _debounce = setTimeout(() => {
        const query = (ev.target as HTMLInputElement).value;
        console.log(query);
      }, 300);
    };
    this._onKeyDown = (ev: Event) => {
      const keyEvent = ev as KeyboardEvent;
      if (keyEvent.key === "ArrowUp" || keyEvent.key === "ArrowDown") {
        keyEvent.preventDefault();
      }
    };

    const input = document.createElement("input");
    input.addEventListener("input", this._onInput);
    input.addEventListener("keydown", this._onKeyDown);

    const list = document.createElement("ul");
    list.innerHTML = `
      <li>TEST 1</li>
      <li>TEST 2</li>
      <li>TEST 3</li>
      <li>TEST 4</li>
      <li>TEST 5</li>
    `;

    this._container.appendChild(input);
    this._container.appendChild(list);
  }

  getDefaultPosition(): maplibreControlPosition {
    return "top-left";
  }

  onAdd(map: Map) {
    this._map = map;

    return this._container;
  }

  onRemove() {
    if (this._container?.parentNode) {
      this._container.parentNode.removeChild(this._container);
    }

    this._map = undefined;
  }
}
